insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a8b31814-f2f1-4955-ab27-0170ee663364', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '모든 유닛(소환수·소환술사·침략자)은 동일한 능력치 체계를 공유한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f07b9107-3be6-4625-bbb6-3133213e946a', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '유닛은 공격력·공격 속도·사거리·치명타 확률·치명타 배율·피해 증가·최대 체력·방어력·이동 속도·쿨타임 감소의 10종 능력치를 가지며, 각 능력치는 기획서 표에 정의된 효과를 가진다.', '오구현', '오구현 : 단일 공격력·단일 방어력 포함 10종이어야 하는데, 물리/마법 공격력·물리/마법 방어력으로 분리되고 상태저항력·받는 피해 감소가 더해진 14종으로 되어있다', 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5bb4ed11-3587-4c91-98bb-81a020098377', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '각 능력치의 단위·범위: 공격력 0~무한(정수)·공격 속도 0.1~무한(실수)·사거리 0~무한(실수)·치명타 확률 0~100%(기본 0%)·치명타 배율 0~무한%(기본 50%)·피해 증가 0~무한%·최대 체력 1~무한(정수)·방어력 0~95%·이동 속도 0~무한(실수)·쿨타임 감소 0~90%.', '미구현', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e6ab3fd3-eaa5-408f-b063-e3f271766c3d', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '본 게임은 공격 타입을 물리/마법으로 분리하지 않고, 단일 공격력·단일 방어력 능력치만 사용한다.', '오구현', '오구현 : 공격력·방어력이 하나씩이어야 하는데, 물리/마법으로 나뉜 공격력·방어력을 별도로 가진다', 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1c87ab57-6a8e-4d9d-b732-408808bc3150', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '각 능력치는 기본 스탯과 추가 스탯으로 구성된다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('6c83c4cd-6cc9-4e42-a1fa-1d1522e9d001', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '기본 스탯은 유닛이 본래 가진 능력치다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('386a644f-3967-49d0-aae2-7603ebfa4055', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '추가 스탯은 시너지·전술지원·버프 등 외부 효과로 증감하는 능력치다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('030a2730-e25d-472d-ac5f-ff7cea2cf26d', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '최종 스탯은 기본 스탯과 추가 스탯의 합이며, 전투에는 최종 스탯이 적용된다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d84391c3-ef14-41c1-925c-eb0ace911c6b', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '외부 효과는 수정자를 통해 유닛의 스탯을 변경하되, 수정자의 존재 자체는 플레이어에게 노출되지 않는다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7189c2ca-3870-410f-ad1a-bd78e5f66eed', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '수정자는 고정값(정해진 수치를 더함)과 비율(비율만큼 올림)의 두 종류로 구분된다.', '완료', null, 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3e4404ed-d631-4f26-af17-39434db81bd1', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '각 수정자는 출처를 가지며, 출처가 된 효과가 해제되면 그 수정자만 사라진다(상태 효과 모델로 표현).', '완료', null, 10);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7d4bb98a-50b0-42a6-9e87-e8b6a3916ece', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '수정자가 추가되거나 빠지면 최종 스탯이 자동으로 다시 계산된다.', '완료', null, 11);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7e9cc8cf-6be5-4d11-aa6b-135ce93fade4', 'c4ac8470-f47e-4aa0-937a-ac6ccd221aa8', null, '최종 스탯이 바뀌면 유닛의 행동(공격 속도·이동 속도·사거리 등)에 즉시 반영된다.', '완료', null, 12);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('574394fa-8e0d-45f7-9516-26c9d5b4d865', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '모든 유닛의 데미지는 동일한 데미지 계산 공식으로 산출된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5a912020-3374-4b9e-9312-b4630b0f7332', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '데미지는 기본 데미지 결정 → 치명타 적용 → 방어력 적용 → 피해 증가 적용 → 최종 확정의 순서로 계산된다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('23f1fc82-5681-4826-a8b1-2dba5d055401', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '일반 공격의 기본 데미지는 공격자의 공격력과 같다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('41aa81bb-a95b-49aa-9bc7-b8d0167a453e', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '스킬의 기본 데미지는 공격력에 스킬 계수를 곱한 값이다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1cf358c6-2533-4676-9a62-5598d8a9b5f3', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '치명타 확률에 따라 치명타가 발생하며 발생 시 기본 데미지에 치명타 배율을 곱하고, 치명타 확률은 100%를 초과하지 않는다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('03cddcb3-870f-4987-aaac-63a72ad4f1f8', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '방어력은 피해 감소율(%)에 직접 대응한다(방어력 30 = 30% 감소).', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5dbeb8b2-880a-4e69-bdae-89f97117bead', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '방어력은 증감 분리 곱연산으로 계산되어, 누적할수록 효율이 체감하고 피해를 완전히 0으로 만들 수는 없다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a73e4d9d-55c1-4475-9e1f-100001b540ef', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '공격자의 피해 증가 수치만큼 데미지가 늘어나며, 여러 출처의 피해 증가는 합연산으로 먼저 더한 뒤 곱한다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('75324470-0f88-421e-87ed-7f513c98e3e0', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '최종 데미지는 소수점을 버리고 0 이상으로 확정된다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d4fa3838-eb98-42c0-9721-c6331363862e', '040c330e-010f-4047-bba9-cd2510e5a89b', null, '곱연산으로 누적되는 스탯은 증가끼리·감소끼리 각각 곱연산한 뒤 총 증가분에서 총 감소분을 빼서 최종값을 구하며, 모든 스탯에 적용된다.', '오구현', '오구현 : 증감 분리 곱연산이 모든 능력치에 적용되어야 하는데, 방어력에만 적용되고 나머지 능력치는 단순 합산으로 누적된다', 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b3593237-2d58-4f63-901a-2ae17caeb6cf', 'dca5b9c0-c626-49c4-966a-f428d0dfb52d', null, '유닛의 모든 공격은 단일 공격력 능력치에 기반하며, 공격 타입(물리/마법) 구분이 없다.', '오구현', '오구현 : 공격 타입 구분 없이 하나의 공격력으로 싸워야 하는데, 공격력이 물리/마법으로 나뉘어 있고 평타는 항상 물리 공격력으로만 계산된다', 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('6f0371fc-ff0e-4a4c-a19c-9214680dd2a1', 'dca5b9c0-c626-49c4-966a-f428d0dfb52d', null, '평타와 스킬은 모두 데미지 계산 공식을 따른다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('51f88ce2-0e38-468f-aab2-f32221aecea1', 'dca5b9c0-c626-49c4-966a-f428d0dfb52d', null, '유닛은 공격 속도에 따라 초당 정해진 횟수만큼 공격하며, 선딜레이와 무관하게 공격 속도가 정한 주기에 맞춰 공격한다(공격 속도 1이면 1초에 한 번). 〔함의〕', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0aa13cb1-c030-4c66-9fe2-ccbcdb8daee2', 'dca5b9c0-c626-49c4-966a-f428d0dfb52d', null, '공격은 항상 명중한다(명중·회피 능력치가 존재하지 않는다). 〔함의〕', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f2719f0f-7399-476a-9b5e-620495b44f93', '4ad6fe24-95e4-4b7c-8348-cb38fe38d5c8', null, '유닛은 자기 사거리 안에 들어온 대상을 자동으로 타겟한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d01beb79-7ac6-444e-aa2b-8950da9b81fe', '4ad6fe24-95e4-4b7c-8348-cb38fe38d5c8', null, '타겟 우선순위의 기본 규칙은 가장 가까운 대상이며, 사거리 안에 여럿이면 최근접 대상부터 타겟한다(동거리 동점은 실수 사거리 계산이라 거의 없음).', '오구현', '오구현 : 가장 가까운 적을 노려야 하는데, 거리와 무관하게 사거리에 먼저 들어온 적부터 타겟한다', 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1c314ce5-90f2-4af5-bcc2-7131a148ba43', '4ad6fe24-95e4-4b7c-8348-cb38fe38d5c8', null, '현재 타겟이 다운되면 유닛은 다음으로 가장 가까운 대상으로 재타겟한다.', '오구현', '오구현 : 타겟이 쓰러지면 그다음으로 가까운 적으로 옮겨가야 하는데, 거리와 무관하게 사거리에 들어온 적부터 다시 타겟한다', 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2c255ad4-1f07-4ccc-a49d-1c8451e29147', '4ad6fe24-95e4-4b7c-8348-cb38fe38d5c8', null, '유닛은 적대 진영의 대상만 타겟한다(소환수·소환술사는 침략자를, 침략자는 소환수·소환술사를 타겟). 〔함의〕', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b780e97b-8f02-4d91-bc5b-c8a1e15317a6', '4ad6fe24-95e4-4b7c-8348-cb38fe38d5c8', null, '타겟이 사거리를 벗어나면 소환수는 대기 상태가 되고, 침략자는 사거리 안에 다음 소환수가 들어올 때까지 왼쪽으로 진군한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('afd45ac7-87bb-43bc-b388-92b009dd6097', '251554e6-e265-4d44-86f3-a7ff112b9c92', null, '유닛의 사거리는 유닛을 중심으로 한 원형(반경 기반)이며, 레인에 묶이지 않는 2D 전방향이고 순수 거리 기반으로 작동한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a8e35498-2cb7-4fb7-8683-55cfba3b9a14', '251554e6-e265-4d44-86f3-a7ff112b9c92', null, '다른 레인에 있는 대상도 사거리(원) 안에 들면 타격할 수 있다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4e8edddb-b977-480d-8880-83f2e540b41c', '251554e6-e265-4d44-86f3-a7ff112b9c92', null, '사거리 반경은 유닛마다 다르며, 근접형은 작은 반경, 원거리형은 큰 반경을 가진다(구체 수치는 콘텐츠·스케일링 위임).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('90550608-9fc8-47f7-b784-2e3e8639f6fd', 'a5893e61-ebb2-4169-bf0d-77d6de7db4b6', null, '스킬은 쿨타임 기반으로 동작하며, 쿨타임은 기본적으로 스킬을 사용하는 시점부터 시작한다(형태별 변형은 콘텐츠 기획).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ba18e25b-8a89-47a0-97a1-112846c10a88', 'a5893e61-ebb2-4169-bf0d-77d6de7db4b6', null, '스킬의 기본 데미지는 공격력에 스킬 계수를 곱한 값이다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4c0c569a-1478-4774-8e4d-8977dd730b50', 'a5893e61-ebb2-4169-bf0d-77d6de7db4b6', null, '스킬 쿨다운은 쿨타임 감소 능력치만큼 퍼센트로 줄어든다(예: 쿨타임 감소 10%면 쿨다운 10% 감소).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ed7de3a5-c32e-4876-bade-2be7e1632f40', 'cb87853b-ac95-4faf-b069-170fbbd6ec19', null, '유닛이 어떤 상태에 있는지(시너지·슬로우·버프·디버프 등이 적용된 상태)는 ''상태 효과''라는 하나의 시스템으로 표현·관리된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e85aa241-de4c-4fc4-81c7-63ac89f7bcd9', 'cb87853b-ac95-4faf-b069-170fbbd6ec19', null, '유닛의 스탯 계산은 유닛이 보유한 상태 효과를 바탕으로 이루어진다(수정자는 상태 효과로 표현된다).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b4ac8af2-42d7-4009-9795-3a0f6445adb2', '72f3db1b-2cfc-4dfc-9eb1-3fc465cbcbff', null, '유닛은 HP가 0이 되면 전투 불능(다운) 상태가 되며, 다운 이후 처리는 종류마다 다르다(소환수=비활성화 후 정비 복구, 침략자=소멸).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d45f3f1a-a816-4d0f-bdc5-3070f915a54e', '72f3db1b-2cfc-4dfc-9eb1-3fc465cbcbff', null, '다운된 유닛은 비활성화되어 더 이상 행동(공격·스킬)하지 않는다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('eac987dd-cc13-4ee0-a792-cc9387184a93', 'ee0b45e4-1cac-4628-b529-5ce55936f5d4', null, '플레이어는 유닛의 역할군을 아이콘으로 구분할 수 있다(현재 체력바 왼쪽, 정확한 위치·형태는 디자인 기획).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('28744a6c-0d45-4692-8631-6f511dd28be5', 'ee0b45e4-1cac-4628-b529-5ce55936f5d4', null, '플레이어는 인게임에서 유닛의 능력치를 확인할 수 있다(능력치 조회 UI 제공).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('889e02d8-217c-4e49-9b5a-bb3cd2f780f1', 'ee0b45e4-1cac-4628-b529-5ce55936f5d4', null, '전투 중 유닛의 체력바를 표시한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('fee40ec5-61ef-4891-822a-f2b7bf448f9e', 'ee0b45e4-1cac-4628-b529-5ce55936f5d4', null, '능력치 UI는 최종 스탯 값만 표시하고 수정자의 출처는 노출하지 않으며, 유닛이 보유한 상태 효과는 표시한다.', '미구현', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2e52cb46-2d68-47d1-80c6-4dd27770a35f', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '각 소환술사는 고유한 소환수 6체를 보유한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('298cc70e-9a9d-456c-aa5c-f7a2e3c82e1d', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '한 전장의 소환수 풀은 출전한 4 소환술사의 소환수를 합쳐 총 24체(4×6)로 구성된다.', '오구현', '오구현 : 출전한 4 소환술사의 소환수로 전장 풀이 짜여야 하는데, 편성과 무관하게 미리 정해진 고정 목록에서 소환수가 등장한다.', 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('87ffa35d-5dcf-4428-9c9e-8717cb99bc3e', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '소환술사별 소환수 풀은 서로 겹치지 않는다.', '미구현', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c7832b16-4ab2-4901-a9d3-e5581d0d7724', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '소환수 사이의 강도 차이는 소환수 종류 자체가 아니라 합성 성급으로 만든다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f7852a83-6455-47dc-9068-96a485cf54e5', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '각 소환수는 탱커·평타 딜러·스킬 딜러·서포터의 4개 역할군 중 하나에 속한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f86dc491-408f-41b7-bf80-bacc8b98095a', 'f7c5f809-4671-4641-bf9c-e4aef64a4690', null, '각 소환술사의 6체 역할군 구성은 정해진 소환수 분포 유형 표 중 하나를 따른다.', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('166224c2-0117-483f-bae4-7935d7046bfb', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전장은 레인(가로 행) × 열로 구성된 배치 그리드를 가지며, 크기는 4 레인 × 8 열이다(추후 밸런스 기획에서 조정 가능).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('04de051a-9495-478d-8316-953ebb15173e', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '그리드의 좌측이 아군 배치 영역이고, 우측 끝 너머가 침략자 스폰 영역이다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f41b7bf3-5c4e-45ed-94a9-81d10014b013', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '아군 소환수는 그리드 칸에만 배치할 수 있다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7858b6e9-6349-4d06-af3c-9ad8a4c5b69e', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '아군 소환수는 전투 중 이동하지 않고 배치된 자리에 고정된다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0103f038-4a0b-478c-8dcf-b200ee4174a6', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '한 칸에는 소환수 1체만 배치할 수 있다(여러 체를 겹쳐 두는 예외는 없다).', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('701fe6a4-ce74-4f05-b71f-4805d142e039', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전장에 배치할 수 있는 소환수 수는 배치 상한에 의해 제한된다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('67907a28-e9d4-41ec-aef9-9c40b8d9247b', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '침략자와 소환수는 같은 칸에 겹칠 수 있다(충돌·점유 없음).', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8a9062bc-134c-4b62-91fb-ec99a2db1dbc', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '침략자는 소환수에 물리적으로 막히지 않으며, 사거리 안에 타겟이 생겨 공격하느라 멈출 뿐이다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c6f527bb-f002-48de-b830-3349e12b77a2', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '플레이어는 정비 페이즈에서 보유 소환수를 그리드 칸에 배치한다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8b201ebe-7023-40b9-84ee-ac61b8bea505', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '플레이어는 정비 페이즈에서 소환수의 위치를 자유롭게 이동·교체(스왑)할 수 있다.', '완료', null, 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('97df43ea-0985-4e41-9e3e-cc680a1c40ae', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전장에 올리지 않은 소환수는 벤치(대기석)에 보관되며, 벤치는 8칸이다(추후 밸런스 조정 가능).', '완료', null, 10);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e52fb0c0-a3aa-4746-a950-32db50b8d624', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '벤치(대기석)가 가득 차면 추가 소환이 불가능하다.', '완료', null, 11);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0124f200-3b05-4b41-948a-ef127d07e734', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전투 페이즈 동안에는 소환수의 위치 변경·교체가 불가능하다.', '완료', null, 12);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('965de181-dc54-4fe1-93a8-ab5afcc8f32b', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전투 페이즈 동안에는 소환수를 전장에 새로 배치할 수 없다.', '완료', null, 13);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bcd73347-e16f-4f14-ada4-87b8deb714db', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '소환수를 한 체도 배치하지 않은 채로도 전투를 시작할 수 있다(최소 배치 수 제약 없음).', '완료', null, 14);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d34affb2-611a-45f2-9ca8-7f9c2930c2ae', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '소환수를 다른 소환수가 있는 칸(전장 칸 또는 벤치 슬롯)으로 드롭하면 두 소환수의 위치가 서로 바뀐다(스왑); 벤치↔전장 이동도 이 스왑으로 처리된다.', '완료', null, 15);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('71ad917c-f858-400f-b1a5-ec0e0c0ab4bd', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '배치 상한에 도달한 상태에서 소환수를 새로 배치하려 하면 배치되지 않고, 화면 중앙에 ''배치 상한에 도달했습니다'' 버블 메시지로 거부를 알린다.', '오구현', '오구현 : 화면 중앙에 ''배치 상한에 도달했습니다'' 문구여야 하는데, 드래그 위치에 ''배치 한계 초과!'' 문구로 표시된다.', 16);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2f842c33-2254-4b7c-ae33-21499879dbc9', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '전투 페이즈에 소환수 배치·이동·교체를 시도하면 적용되지 않고, 화면 중앙에 ''전투 중에는 소환수 배치를 수정할 수 없습니다'' 버블 메시지로 거부를 알린다.', '오구현', '오구현 : 화면 중앙에 지정 문구여야 하는데, 드래그 위치에 ''전투 중에는 배치할 수 없습니다!''/''전투 중에는 이동할 수 없습니다!''로 표시된다.', 17);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('709e5842-3c48-42e7-91d2-e1926f995a27', '4d9dc856-05de-46ab-86fc-5f48b2801f2d', null, '소환수를 그리드 밖이나 배치 불가 영역에 드롭하면 별도 표시 없이 원래 자리로 되돌아온다.', '완료', null, 18);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3549290d-f1bf-4c08-8e2e-fe66a6dca6a9', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '소환수는 성급(별 등급)을 가진다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5b9f046b-a02a-4d87-9f7f-139d28b4b879', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '동일 소환수 3개를 모으면 상위 성급으로 승급한다(1성×3→2성, 2성×3→3성).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ebecdcd4-44d3-4358-9468-ab3e22817a3f', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '3성 이후에는 2성 소환수를 하나씩 더해 강화 합성하며(3성+2성→3성+1강, 이후 1강씩 누적), 강화 단계 상한은 +10강이다.', '오구현', '오구현 : 강화가 +10강에서 멈춰야 하는데, 상한 없이 계속 강화할 수 있다.', 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1bbb88f7-3b62-418f-8d7c-9ecec113b4dc', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성의 동일 소환수 판정은 같은 종류이면서 같은 성급인 소환수 3개를 요구한다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('426ce108-796c-4005-b5de-7cc63041b322', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성 대상에는 대기석(벤치)과 전장에 있는 소환수가 모두 포함된다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f6a32224-6e22-459b-b356-9bdbe96f046b', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성은 정비 페이즈에서만 발생하며, 전투 중에는 합성되지 않는다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a78e0710-db43-458f-a512-208dd6429500', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '동일 소환수 3개가 모이는 승급 합성은 조건 충족 시 자동으로 일어나며, 플레이어가 막거나 미룰 수 없다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3d0ff460-2184-4eb7-98c5-11fcc1eaf591', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '강화 합성(3성+2성)은 동일 3개 자동 승급과 달리, 플레이어가 2성 소환수를 3성 소환수에 드래그 앤 드롭해 직접 수행한다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bbfeadef-034a-4742-a608-0ea1b01a92af', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성 결과 소환수는 재료 중 화면상 가장 왼쪽 위에 있던 재료의 위치에 생성되며, 벤치는 전장 아래에 놓이므로 전장 재료가 섞이면 전장에 생성된다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d3bc2ac6-f5d1-40d5-bccb-2dc17df3165f', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성 결과로 다시 3개 조건이 충족되면 자동으로 연쇄 합성된다(같은 종류·성급이 3개를 넘겨 쌓이지 않는다).', '완료', null, 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('650fb01c-69d8-4c92-be04-d902fb9cc865', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '소환수의 기본 스탯은 성급에 따라 정해지며, 승급하면 기본 스탯이 강화된다(구체 수치·곡선은 밸런스·스케일링·콘텐츠 기획).', '완료', null, 10);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('58113736-ae52-484a-825b-dae67e5fe8f5', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '승급하면 경우에 따라 소환수의 스킬이 강화된다(어느 성급에서 어떻게는 콘텐츠 기획).', '미구현', null, 11);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d648a91d-f188-416f-9bc9-72bae18a1269', '05ef9cbe-d0c3-48f6-8205-05b662e526d3', null, '합성으로 재료가 소비되고 결과가 생성되면 그리드 칸 점유·배치 상한 사용량·시너지 카운트가 갱신된다. 〔함의〕', '완료', null, 12);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b310b0b1-459d-4006-a4d9-d96d2a70160b', 'c75d3203-eded-4482-9693-91e137c513d2', null, '소환수는 소환 터미널에서 소환되어 대기석에 생성된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('98abc24b-c8f7-472b-85f8-22ffa5c90c8e', 'c75d3203-eded-4482-9693-91e137c513d2', null, '소환수는 환원(판매)으로 보유에서 제거되어 마나로 되돌릴 수 있으며, 환원은 정비 페이즈에서만 가능하다(상세는 소환터미널 정본).', '오구현', '오구현 : 환원(판매)이 정비 페이즈에서만 가능해야 하는데, 전투 중에도 소환수를 환원할 수 있다.', 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1da1465a-18b8-455e-8b61-503727c7ac07', 'c75d3203-eded-4482-9693-91e137c513d2', null, '전장에 배치된 소환수를 환원하면 그리드 칸·배치 상한 점유에서 빠지고 시너지 카운트가 다시 계산된다. 〔함의〕', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('86c7386c-a473-4b84-ba7e-99e37a2cbcf7', 'c75d3203-eded-4482-9693-91e137c513d2', null, '라운드(전투 페이즈) 종료 시 전장에 배치된 소환수는 HP가 전부 회복된 상태로 다음 라운드를 시작한다(벤치 제외).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('983675de-2993-4133-9b38-a8e5aeffad9e', 'c75d3203-eded-4482-9693-91e137c513d2', null, '다운된 소환수도 라운드 종료 시 HP 전부 회복 상태로 복귀한다(라운드 중 부활은 콘텐츠 영역).', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('66be1ed6-3b0e-4421-b28e-794efc30b718', 'c75d3203-eded-4482-9693-91e137c513d2', null, '전장에 배치된 소환수의 스킬 쿨다운은 라운드 종료 시 초기화된다(벤치 제외).', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ea79f0e6-dfc7-49dd-9880-e03e14409e5a', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '소환수는 탱커·평타 딜러·스킬 딜러·서포터의 4개 역할군으로 구분된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('01601430-019b-42c6-8783-b202f52307c8', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '각 역할군은 고유 컨셉을 가진다 — 탱커: 높은 체력·방어력으로 전열 유지·피격 분담 / 평타 딜러: 평타 기반 지속 딜 / 스킬 딜러: 평타가 약한 대신 스킬 의존으로 변수 창출 / 서포터: 아군 체력 회복·유지·보조.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('647e988a-37b5-4af6-bfec-66f744c977a9', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '스킬 딜러의 공격력 능력치는 다른 역할군과 동일하며, 차별화는 능력치 분리가 아니라 스킬 의존도로 이루어진다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c01e1e56-2d91-4a36-b9f6-36be48008bb7', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '역할군은 전용 슬롯·전용 전투 규칙 등 별도의 시스템적 구분을 갖지 않으며, 전투 로직은 역할군을 직접 참조하지 않는다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c92d0e74-e61b-448c-ad6d-34b425b0750f', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '역할군은 유닛의 스탯 분포와 아이콘으로 구분된다(역할군별 구체 스탯 분포는 소환수별 콘텐츠 기획).', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e5233e32-120f-42c0-9a08-cd3ed7fcb7e7', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '역할군은 그 자체로 효과를 내지 않고, 상위 시스템(심상 효과·소환수 특성 등)의 대상 필터/조건으로 활용된다.', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('04079a61-3cc9-4ea0-9929-0a8a3386f489', '6bad3966-7ea9-4f51-9b4c-0a1f41e28e52', null, '역할군은 소환수 특성 부여 확률 보정의 기준이 된다(역할군에 맞는 효과가 더 높은 확률로 부여됨).', '미구현', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5c5c3cc0-1680-4436-932d-b5ee7f1453d3', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사는 전투 능력치를 가지고 전장에서 직접 공격하고 피격된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c51bb6f7-12f7-462c-be7b-43f1f7ba5e0d', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사는 유닛 공통 능력치 체계와 데미지 공식을 소환수와 동일하게 사용하며, 시스템상 공통 능력치를 모두 보유하되 플레이어에게는 주요 능력치만 표시한다.', '미구현', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ad248d21-174e-445f-aceb-3f50bbccf5c8', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사는 성급(별 등급)이 없다.', '오구현', '오구현 : 소환술사는 성급이 없어야 하는데, 체력바에 성급(별 등급) 표시가 붙어 있다', 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8385b673-0382-4843-a2b4-056f1fd3c5e9', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사의 기본 능력치는 성급이 아니라 별도 기준값으로 정해진다(기준값 수치는 밸런스·스케일링 위임).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c7ed665b-c432-4370-897d-27e9f2f89116', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사의 능력치는 육성(레벨업·심상 각성)으로 강화된다.', '미구현', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('6b6cc697-37aa-4ac6-b2ca-cc5b6f8787d3', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사를 레벨업하면 본체의 전투 스탯(HP·공격력 등)이 함께 상승한다.', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('de4a0531-569b-4c19-9416-db8b8de0dd42', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사의 기본 사거리는 1(근접)이다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('65d973c8-91a4-4c97-a9c0-ecd5b7914983', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '소환술사는 평소 직접 전투에 개입하지 않고, 침략자가 자기 레인 끝에 도달했을 때 교전·반격한다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ddf99848-32ba-4e88-8dea-67b5828ecccc', '88bde479-6a5a-48ba-91b3-2c2bf208f6ea', null, '심상 효과에 따라 소환술사가 직접 공격하거나 사거리를 갖는 등 전투 양상이 달라질 수 있다(구체 변형은 콘텐츠 기획).', '미구현', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('63aba6bc-096a-4d3c-9246-ce035d224275', '3ccaede7-4372-4b54-9757-eb030d4e10a1', null, '각 레인 좌측 끝에 소환술사 1명이 1:1로 배치되며(4 레인 ↔ 4 소환술사), 어느 소환술사가 어느 레인에 가는지는 출전 편성 순서대로 정해진다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1a1cf197-71a8-4c53-adb7-258ae9e83753', '3ccaede7-4372-4b54-9757-eb030d4e10a1', null, '침략자가 어느 레인의 끝에 도달하면 그 레인의 소환술사와 교전한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('35120425-e060-441d-8844-81265d7cc23b', '3ccaede7-4372-4b54-9757-eb030d4e10a1', null, '소환술사는 자기 레인 끝의 고정 위치에 자리하며, 전투 중 이동하지 않는다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f2b5e541-bb5e-4004-abb3-dfa690a93156', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '소환술사는 전장 시작 시 자기 레인에 배치되어 등장한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2e5b298d-c18d-4cda-9c16-46e0a79fee93', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '소환술사는 피격에 따라 HP가 감소한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bd805b38-bafe-482c-bdc7-1a81a971ccd9', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '소환술사 중 한 명이라도 HP가 0(다운)이 되면 그 즉시 전투 페이즈가 강제 종료되고 전투 패배로 처리된다(동시 다운도 패배 1회 차감).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a0f821e6-2224-4374-a74e-238037ad2698', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '다운된 소환술사는 정비 페이즈 복귀 시 완전 회복된 상태로 시작한다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bbbbf6bb-77db-4808-a7df-d22709fb18fe', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '소환술사는 라운드(전투 페이즈) 종료 시 완전 회복된 상태로 다음 라운드를 시작한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('44b9aa26-7ad8-4a9d-b0f7-0f6bcf9aa1d8', 'ce722525-4fc3-4fe3-a2c5-97345b30d2ec', null, '소환술사는 일반 상태이상에 걸리지 않고 디버프성 효과만 받으며, 소환술사에게 적용되는 효과는 별도로 명시된다.', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ce999a86-f3eb-4656-aeec-80d6884ca1bf', '1ea13a17-16ad-4dc9-b5c7-0b2d88250d20', null, '각 소환술사는 고유한 심상 효과를 가지며, 심상은 소환술사마다 완전히 고유하다(같은 심상을 가진 다른 소환술사는 없다).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('22019a75-5508-454f-91d2-e62f8170506e', '1ea13a17-16ad-4dc9-b5c7-0b2d88250d20', null, '소환술사의 소환수는 그 소환술사의 심상 효과를 자동으로 보유한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bd1ed253-b8d9-4f41-ba90-ba7c8b434c18', '1ea13a17-16ad-4dc9-b5c7-0b2d88250d20', null, '심상 효과는 출전 편성 시 소환술사 선택에 의해 고정 결정된다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0579938b-81cc-4dbc-bbd1-2dbaaa2fcaa9', '1ea13a17-16ad-4dc9-b5c7-0b2d88250d20', null, '소환술사의 육성 상태(레벨업·심상 각성)에 따라 심상 효과가 강화된다(강화 메커니즘은 육성 외부귀속).', '미구현', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('144e30e7-1631-43ea-ade3-f116f249745c', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '플레이어는 정비 페이즈에서 소환 터미널(상점)을 열고 닫을 수 있다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('778a1a50-cfa9-4785-8c72-87769870b0d8', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 4개의 소환 슬롯에 현재 소환 후보 소환수를 보여준다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ab2c3ed3-082d-4453-a557-45333f2c3472', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 플레이어의 현재 보유 마나를 표시한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('37e8403d-53ea-44e4-b809-4abcf406a07a', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 다음 라운드에 지급될 마나 수입(예상치)을 표시한다. 〔함의〕', '미구현', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2c927cfa-21e8-497a-a736-b6531ce25dad', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 재스캔 버튼을 제공한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f5020852-b4df-4322-a3f8-b358d399a0f9', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 스캔 잠금 버튼을 제공하며, 버튼은 현재 잠금/해제 상태를 나타낸다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('72ef73d4-c5ff-46bf-928f-9bffa5aed705', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '소환 터미널은 배치 상한 증가 버튼을 제공한다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0e04f1d9-fac3-4936-9ed6-ed97a5bc9219', 'f02e336f-5e5b-4e21-9411-ad205d8436af', null, '전투 페이즈에는 소환 터미널이 닫히고 터미널을 여는 버튼도 사라져, 전투 중에는 터미널 조작(소환·재스캔·배치 상한 증가)을 시도할 경로 자체가 없다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3f7ceaf4-6443-41d5-84c2-71d055de09d2', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '소환 터미널은 매번 4개의 소환 후보 소환수를 제시한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('cb610aed-2d4d-4248-9529-80c3c1378a4b', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '플레이어가 소환 후보를 터치하면 마나를 지불하고 그 소환수를 소환한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4bf02eaa-efaa-4de8-a167-2ede7f80528e', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '소환 비용은 소환수의 성급에 따라 1성 1마나·2성 3마나·3성 9마나다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('dc2a8ba1-be8b-414b-b658-3464567c4165', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '소환된 소환수는 대기석(벤치)에 생성된다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a22513bf-c797-49a3-ba23-1c9196e00a95', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '대기석(벤치)에 빈자리가 없으면 소환 후보를 터치해도 소환되지 않는다.', '오구현', '오구현 : 대기석이 꽉 차면 소환 시도가 그냥 막혀야 하는데, 소환수는 안 생기면서 마나는 빠지고 후보 칸도 사라진다', 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c2eb8b56-1ce9-4573-a78f-d3497803715f', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '보유 마나가 소환 비용보다 적으면 소환되지 않는다. 〔함의〕', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7a896337-fdab-4707-be7c-0b84f58df8f2', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '배치 상한이 높을수록 소환 후보로 2성·3성 소환수가 등장할 확률이 생긴다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a0d4fb6c-4774-4185-9c6e-b4d58fd99352', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '대기석(벤치)이 가득 찬 상태로 소환을 시도하면 소환되지 않고, 화면 중앙에 ''대기석이 가득 찼습니다'' 버블 메시지로 거부를 알린다.', '미구현', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('71503be3-796f-48a6-bf4a-bffbf7594d3a', 'e4d1cb16-98e5-46c3-90b6-4baebc0b104e', null, '마나가 부족한 상태로 소환·수동 재스캔·배치 상한 증가를 시도하면 적용되지 않고, 화면 중앙에 ''마나가 부족합니다'' 버블 메시지로 거부를 알린다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('cbed89d7-017e-436f-a92f-3c2627835f8b', '3c87083f-f762-4e18-a3d2-71ecc42b21d7', null, '스캔(리롤)은 터미널의 소환 후보 목록을 다시 뽑아 재구성하는 것이다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a28ec675-4c3c-4f7d-849d-92943a1a5a33', '3c87083f-f762-4e18-a3d2-71ecc42b21d7', null, '스캔은 출전한 소환술사들이 소환할 수 있는 24종 소환수 중 4개를 균등 확률로 뽑으며, 같은 종류가 한 번에 중복으로 나올 수 있다.', '오구현', '오구현 : 출전한 소환술사들이 소환할 수 있는 소환수 중에서 후보가 나와야 하는데, 편성과 무관하게 고정된 후보 목록에서만 나온다', 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('acf1653e-1cda-4e5d-83f9-01ee3eb73386', '3c87083f-f762-4e18-a3d2-71ecc42b21d7', null, '매 라운드 시작 시 터미널이 자동으로 다시 스캔된다(별도 비용 없음).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2efbb1f7-b64f-4cfc-85bf-5941f52b5993', '3c87083f-f762-4e18-a3d2-71ecc42b21d7', null, '플레이어는 재스캔 버튼으로 추가로 다시 스캔할 수 있으며, 수동 재스캔은 마나를 지불한다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5e0b93fb-ee58-4ea5-af9b-daaedc5651a9', '246a7d33-4894-47c4-9462-c554bf0f381f', null, '스캔 잠금은 다음 라운드 시작 시의 자동 재스캔을 막는 기능이다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b9031468-eb0b-4e17-8434-0b058d0208cd', '246a7d33-4894-47c4-9462-c554bf0f381f', null, '스캔이 잠긴 상태로 라운드가 시작되면 자동 재스캔이 일어나지 않고, 잠금은 그 시점에 해제된다(1회 적용 후 소모).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1089a84a-b98a-4be6-9e03-39b5a101c4ef', '246a7d33-4894-47c4-9462-c554bf0f381f', null, '플레이어는 정비 페이즈에서 스캔 잠금을 켜고 끌 수 있다. 〔함의〕', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('838af072-2fb7-46a3-af14-f8afa569fc80', '31f76f73-5a39-4830-afe1-4590c6d627ab', null, '환원은 소환한 소환수를 소환 해제하여 마나를 되돌려받는 것이다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('049d3f14-b28c-4659-8c97-15db3e3980db', '31f76f73-5a39-4830-afe1-4590c6d627ab', null, '플레이어는 소환수를 상점(환원) 영역으로 드래그 앤 드롭하여 환원한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('36969094-20f2-4460-862f-3fde60da5656', '31f76f73-5a39-4830-afe1-4590c6d627ab', null, '환원 회수 마나는 성급별로 1성 1마나·2성 2마나·3성 8마나이며, 3성에 강화 N회가 더해지면 8+N마나다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('668d03f2-0097-45b1-91c7-f8594618fd93', '31f76f73-5a39-4830-afe1-4590c6d627ab', null, '마켓에서 고성급으로 직접 등장해 소환된 소환수도 같은 환원 규칙을 따른다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('99ee1f4f-4675-4f31-b91c-2851bccbf355', '31f76f73-5a39-4830-afe1-4590c6d627ab', null, '환원은 정비 페이즈에서만 가능하다.', '미구현', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7cc2e5ab-db69-4d54-80ce-504fd406d562', '469e0f54-2a3d-4b17-9a6d-1aad09d7fb9c', null, '배치 상한 증가는 전장에 배치할 수 있는 소환수 수(배치 상한)를 늘리는 기능이다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c9db9a83-ee4b-42ea-8c73-22c0832956c0', '469e0f54-2a3d-4b17-9a6d-1aad09d7fb9c', null, '초기 배치 상한은 3이다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e4386ff6-b66d-4972-8c9e-af787a35ec14', '469e0f54-2a3d-4b17-9a6d-1aad09d7fb9c', null, '배치 상한 증가는 마나를 지불해 한 단계씩 올리며, 비용은 상한이 높아질수록 누진한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('287066fd-ac7f-430b-bfd9-07db3193d8a5', 'd2c3ec3f-9a7b-4577-9ff7-099033380295', null, '매 라운드 시작 시 플레이어에게 마나가 지급된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2a8de9db-af5a-402d-9aca-d8d90e82452d', 'd2c3ec3f-9a7b-4577-9ff7-099033380295', null, '라운드 시작 시 지급되는 마나는 기본 지급(라운드에 따라 1~10)과 이자(0~3)를 합한 값이다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2adfe9d5-70c4-4118-8102-cb79f1262c2f', 'd2c3ec3f-9a7b-4577-9ff7-099033380295', null, '마나는 라운드 사이에 사라지지 않고 이월된다. 〔함의〕', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ec57e089-0588-41c1-8dc0-8dded028d4f5', 'd2c3ec3f-9a7b-4577-9ff7-099033380295', null, '마나는 소환·수동 재스캔·배치 상한 증가에 지불되어 차감되고, 환원으로 회수된다. 〔함의〕', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bbe7b900-ba60-4efe-9ebb-8a2b90118851', 'd2c3ec3f-9a7b-4577-9ff7-099033380295', null, '라운드 시작 이자는 보유한 마나 10당 1마나씩 지급되며, 0~3 범위에 따라 최대 3마나다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('14fabedd-4759-4864-9a5d-f5cb4b53b4f3', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '한 전장은 정규 라운드와, 그에 이어지는 엑스트라 라운드로 구성된다.', '미구현', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4657f7fc-ada4-490a-b605-1f196d6c63db', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '각 라운드마다 침략자 웨이브가 등장하고, 그 웨이브를 모두 처치하면 다음 라운드의 정비 페이즈가 시작된다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('43463ec2-0fd0-4a01-a84d-4fdc462aebd0', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '정규 라운드는 캠페인의 정규 진행 구간이며, 라운드 수는 전장의 목표 플레이 타임(약 20분)에 맞춰 정해진다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('310fc01a-6677-4827-a2dc-acfd1333b9f2', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '정규 라운드를 모두 클리어하면 임무 완수(승리 확정)로 처리되고 클리어 보상이 확정된다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4e3827c8-b302-4b77-84e1-ce4f198602dd', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '정규 라운드 단계에서 허용되는 전투 패배 횟수는 3회다.', '오구현', '오구현 : 3회까지 패배해도 계속 도전할 수 있어야 하는데, 2회 패배에서 바로 임무 실패로 끝난다', 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0a0139a5-6788-4bb7-aa8f-b991131a2203', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '엑스트라 라운드는 정규 라운드를 모두 클리어하면 자동으로 시작되는 추가 구간이다(플레이어가 진입을 선택하는 것이 아니라 자동 연장된다).', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('716ebcfe-fd3b-4b04-a781-27b0e14709ee', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '플레이어는 엑스트라 라운드 도중 언제든 ''클리어 확정 후 퇴장''을 선택해 전장을 마칠 수 있다.', '미구현', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('907c521e-d908-417e-b3e7-9ba750647135', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '엑스트라 라운드에서는 잔여 패배 횟수가 0으로 취급되어, 1회 패배하면 즉시 전장이 종료된다(임무는 이미 완수 상태라 실패가 아니라 그 시점까지의 보상 배수로 정산하고 종료된다).', '미구현', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('fdfedb76-75c6-4d53-a19d-bd39e5e35427', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '엑스트라 라운드는 거듭할수록 난이도가 가파르게 상승한다.', '미구현', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('894c9f44-9fdf-482e-ab9c-317508a6ae7f', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '특정 특수 전장(보스 전장 등)에서는 엑스트라 라운드가 비활성화될 수 있다.', '미구현', null, 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e24a440b-8d4a-44a7-ac3c-bcb1cb81f83d', 'ae3034c0-8b76-4957-8078-1552ec95365e', null, '엑스트라 라운드의 ''클리어 확정 후 퇴장''은 전장 화면의 버튼으로 노출되며, 버튼을 누르면 ''전장을 클리어하고 퇴장하시겠습니까?''라는 확인 메시지가 표시되고 확인하면 승리(클리어 확정)로 처리된다.', '미구현', null, 10);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d4987ada-c514-482c-8cbd-9cabccf0d68c', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전장은 정비 페이즈(준비)와 전투 페이즈(웨이브)가 번갈아 진행된다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('45494d38-f96f-4d24-a39d-f29c90eb9e28', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '정비 페이즈에서 플레이어가 전투 시작을 터치하면 전투 페이즈가 시작된다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('10db8989-b3ac-487f-9559-873a9d39b5e4', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '정비 페이즈에서 플레이어는 전투 준비 행동(소환 터미널 이용·소환수 배치/교체/합성·전술 지원 선택·다음 웨이브 프리뷰 확인)을 한 뒤 전투를 시작한다.', '미구현', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('47ead07f-7245-4363-afb0-0e8e299be699', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전투 페이즈에서는 웨이브의 침략자가 스폰되어 진군하고, 배치된 소환수가 이동 없이 제자리에서 자동으로 전투한다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('95546218-e7d7-4255-857f-eb783cd03520', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전투 페이즈 동안 활성화된 시너지 효과와 선택된 전술 지원 효과가 계속 적용된다.', '미구현', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8e58ac0b-22b9-420f-b5e1-75792299b74b', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전투 페이즈 동안에는 소환수의 배치·이동·교체뿐 아니라 소환·재스캔·배치 상한 증가도 모두 불가능하다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('9b00cc5f-069f-4705-bd5c-8b58efcb5388', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전투 페이즈는 웨이브의 침략자를 모두 처치하면 전투 승리로 종료된다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('82ebc0a8-5017-4cb7-b924-19679bf840ba', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전투 페이즈는 소환술사 중 한 명이라도 다운(HP 0)되면 그 즉시 전투 패배로 강제 종료된다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e6913ecf-edcb-4fcf-841e-096e537291d3', 'af884202-7f13-4d2d-8a7b-22756780e92a', null, '전장 종료 조건에 해당하지 않는 전투 종료 후에는 정비 페이즈로 전환된다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('113815f6-f445-4350-96ff-c458d2bdb812', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '정규 라운드를 모두 클리어하면 임무가 완수되어 클리어 보상이 확정되고, 이어서 엑스트라 라운드가 자동으로 시작된다.', '미구현', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ad2f8aae-93c8-497d-bb3e-e09055a51bb5', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '엑스트라 라운드 도중 ''클리어 확정 후 퇴장''을 선택하거나 엑스트라 라운드에서 패배하면 정산 화면이 표시되며 전장이 종료된다.', '미구현', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('4eaa42c9-ecbc-4ea4-b3d5-bfab84964422', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '정산 화면에는 전투 정보와 보상(엑스트라 라운드 배수를 포함한)이 표시된다.', '미구현', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('287a0a83-c407-45ff-894d-da54fb2fb44b', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '정규 라운드에서 전투에 패배하면 그 라운드는 클리어로 인정되지 않고, 라운드 카운터가 유지된 채 정비 페이즈로 돌아가 같은 라운드를 다시 도전한다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('b52ef275-36ae-4231-aced-4fa6d66e29c7', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '정규 라운드에서 전투에 패배하면 잔여 패배 횟수가 1 감소한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1226ce44-2413-4ef7-9f60-46c99097177f', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '전투 패배 후 정비 페이즈로 복귀하면 모든 소환수와 소환술사가 완전히 회복된 상태로 시작한다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('476baae4-1c45-421e-9840-d4c1e218c4f7', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '정규 라운드에서 전투 패배가 누적 3회가 되면 임무 실패로 전장이 패배 종료된다.', '오구현', '오구현 : 3회 패배해야 임무 실패로 끝나야 하는데, 2회 패배에서 임무 실패로 종료된다', 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('11d47848-eddb-4694-ad2e-4a1a2d719835', '1437cc26-28a6-4eae-8f5e-b2e3f59cc84a', null, '임무 실패 시 플레이어는 재도전하거나 로비로 나갈 수 있다.', '오구현', '오구현 : 재도전과 로비 나가기 중 고를 수 있어야 하는데, 확인을 누르면 전장 선택 화면으로 나가는 선택지 하나뿐이라 재도전을 할 수 없다', 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('99a59e8b-7358-4cb5-b1f9-e91101bbbbcc', 'be32ff2c-0e8a-4883-a8cf-bdbbec84d9b4', null, '한 전장의 최종 보상은 정규 라운드 클리어 보상에 엑스트라 라운드 배수를 곱한 값이다.', '미구현', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('115012b9-b05c-45bc-82c9-ab14304e96cc', 'be32ff2c-0e8a-4883-a8cf-bdbbec84d9b4', null, '엑스트라 라운드 배수는 엑스트라 라운드를 1라운드 클리어할 때마다 +0.1씩 누적된다.', '미구현', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3b69a436-c57b-40f1-998b-ee9c1709994d', 'be32ff2c-0e8a-4883-a8cf-bdbbec84d9b4', null, '정규 라운드 클리어 보상으로는 강화 재화와 가챠 재화가 제공된다(구체 종류 비중·수량은 콘텐츠·밸런스 위임).', '오구현', '오구현 : 클리어 보상이 강화 재화·가챠 재화여야 하는데, 마나·경험치로 정해져 있고 그마저도 실제로 지급되지 않는다', 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('3f4f7097-eaf9-40ff-858c-b2b7947d423b', '96fe1247-7969-4d75-bd39-d793b79d6df6', null, '전장은 현재 라운드 진행 상황을 라운드 카운터(예: 5/6) 형태로 표시한다.', '오구현', '오구현 : 현재/전체 라운드(예 5/6)로 보여야 하는데, 전체 수 없이 "N 라운드"로만 표시되고 그마저 적 진영을 볼 때만 노출된다', 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c8582844-cf30-4d2d-9aae-800973b709e2', '96fe1247-7969-4d75-bd39-d793b79d6df6', null, '전장은 현재 잔여 패배 횟수를 표시한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c7e61d7a-ed97-4e13-8240-f3e91e9e302f', '96fe1247-7969-4d75-bd39-d793b79d6df6', null, '정규 라운드를 모두 클리어하면 전장은 임무 완수(승리 확정) 메시지를 표시한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0aa02dd1-a83e-4d04-9460-7f7e52840672', '96fe1247-7969-4d75-bd39-d793b79d6df6', null, '전장은 현재 페이즈(정비/전투)를 플레이어가 구분해 인지할 수 있게 표시한다. 〔함의〕', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('bbd7a095-aac2-4db2-9a7f-7a00ce4a77dd', 'ddf17b4f-e878-4b94-907c-730d52d92cdf', null, '침략자는 화면 밖 오른쪽 끝(각 레인의 스폰 영역)에서 생성되어, 왼쪽으로 진군하면서 화면 안으로 들어온다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('60299575-5945-4889-9dcc-d6b39e866c8b', 'ddf17b4f-e878-4b94-907c-730d52d92cdf', null, '침략자가 출현하는 레인은 무작위로 정해진다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('fc570faa-d6e2-4450-9c62-178f55559a51', 'ddf17b4f-e878-4b94-907c-730d52d92cdf', null, '침략자 출현은 한 웨이브 안에서 4개 레인에 가능한 한 균일하게 분산되며, 무작위에 기인한 비균일성은 허용된다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5c6b64df-d62b-4f91-a255-24d582605ce3', 'ddf17b4f-e878-4b94-907c-730d52d92cdf', null, '침략자는 한 번에 모두 등장하지 않고, 전투 페이즈 안에서 정해진 시간 간격으로 순차적으로 등장한다(간격 수치는 밸런스 위임).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7d1877ed-0ddb-4cbd-a8f9-a6e9fe49d264', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '각 라운드마다 침략자 무리(웨이브)가 등장한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('d422a9a1-a5c9-49a9-aa6b-4e27ae5c45a4', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '웨이브의 침략자를 모두 처치하면 전투 페이즈가 종료되고 전투 승리로 처리된다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7474da49-3303-4b62-b19b-8c43bd7cb6f4', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '웨이브 구성에 따라 레인별로 침략자가 생성되어 진군한다(개별 웨이브 구성은 콘텐츠 위임).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('c2f74bdb-555a-4cf4-97d1-05cabdede5df', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '플레이어는 정비 페이즈에서 아군 진형 오른쪽 너머(침략자 구역)에 이번 라운드에 등장할 침략자의 종류와 수를 미리 보며, 그리드당 프리뷰 1개에 ''×5'' 같은 형태로 수가 표시된다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e7552171-5f0f-4355-8968-443bc91ea6c8', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '플레이어가 웨이브 프리뷰의 침략자를 클릭하면 유닛 정보 창이 열려 그 침략자의 사진·스킬 정보·능력치를 확인할 수 있다.', '미구현', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5722449b-33b2-4790-9112-eeb5c0996228', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '전투 페이즈 중에는 화면 오른쪽 상단 UI 패널에 ''남은 침략자 수: n'' 형태로 남은 침략자 수가 표시된다.', '미구현', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('dd94af9e-cf91-44c8-b417-08bf068f749c', '55f4e74d-f387-43e3-b7ae-820472ea3c6d', null, '침략자가 처치되면 그 웨이브의 남은 침략자 수에서 빠진다(소멸·처치 보상은 라이프사이클 정본).', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1251fd33-ba07-4ffb-a62a-c8598c5fdef4', 'bb72e041-9010-451e-b83f-1a2dca5b0e67', null, '침략자는 자기 레인을 따라 오른쪽에서 왼쪽으로 진군한다(진군 속도는 이동 속도 능력치, 값은 밸런스 위임).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('dfab31a4-f4e8-4d94-976f-ef58910fc57b', 'bb72e041-9010-451e-b83f-1a2dca5b0e67', null, '침략자는 사거리 안에 소환수가 들어오면 멈춰서 공격한다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8c8d1846-f7fa-4d27-9358-6125453f1221', 'bb72e041-9010-451e-b83f-1a2dca5b0e67', null, '침략자는 사거리 안에 타겟이 없으면 즉시 다시 진군한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a4d4ff07-0ea9-4163-b445-af1a5c7b7627', 'bb72e041-9010-451e-b83f-1a2dca5b0e67', null, '침략자는 소환수와 물리적으로 충돌하지 않고 같은 칸을 지날 수 있으나, 앞(사거리 안)에 소환수가 있으면 공격하느라 진군을 멈춘다(결과적으로 막는 것과 같은 효과).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a8758d9c-e82f-462b-a296-49aa8315964b', 'bb72e041-9010-451e-b83f-1a2dca5b0e67', null, '침략자가 자기 레인의 왼쪽 끝에 도달하면 그 레인의 소환술사와 교전하며, 이 교전은 소환수와 싸울 때와 동일한 규칙(소환술사 반격 포함)을 따른다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f27372e4-7a72-40f3-bd81-264117d1c941', '2999f8ba-00ac-49d7-96e0-e23be7942fa2', null, '특별한 전장 또는 라운드에서는 보스 침략자가 등장할 수 있다(등장 전장/라운드·보스 고유 메커닉·승리 조건은 콘텐츠·밸런스 위임).', '미구현', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0bbd904b-368a-44ef-ad35-6c4350145ccb', 'b9914a7a-eb38-47ae-9a9b-1cfce3cdf2ca', null, '침략자는 HP가 0이 되면 소멸하여 전장에서 사라진다(소환수가 다운 후 복구되는 것과 달리 즉시 소멸).', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('e1271784-69fd-41ed-b230-a2302e6ec277', 'b9914a7a-eb38-47ae-9a9b-1cfce3cdf2ca', null, '침략자를 처치해도 기본적으로는 보상(마나·재화)이 주어지지 않는다(전술 지원·출격 모듈이 부여하는 경우에만).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('52fdd99c-2454-4461-ae5c-07a186cbff75', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '시너지에는 심상 효과와 소환수 특성, 두 종류가 있다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('824c80e6-f8e1-4301-a9a2-777b571b8887', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '각 소환수는 전장에 진입할 때 두 가지 시너지를 가진 채 시작한다 — 자신의 소환술사에게서 받는 심상 효과와 그 전장에서 배정받은 소환수 특성.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('49f49bb6-7787-42de-a64d-df926e1fa0c8', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '시너지 카운트는 전장에 배치된 서로 다른 종류의 소환수를 세며 같은 종류는 여러 마리여도 한 번만 센다(심상 효과·소환수 특성 두 시너지 공통).', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('dd759ea6-538b-44ae-8267-c2d54d2a79e8', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '배치된 소환수가 다운되어도 그 소환수가 채운 시너지 카운트는 줄지 않고 그대로 유지된다.', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('05fb108a-e47f-4283-9219-15eb4675bb17', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '소환수가 새로 배치되거나 전장에서 제거되면 시너지 카운트를 다시 계산한다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('8585bfb5-3d2e-4afd-8fb1-5aa76806fd80', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '심상 효과는 카운트가 2/4/6에 도달할 때 발동하는 3단계 임계치를 가진다.', '완료', null, 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5183519b-2788-4aa8-80dc-a1e7870a9596', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '소환수 특성은 카운트가 2/3/4에 도달할 때 발동하는 3단계 임계치를 가진다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('2f0a8e72-d4eb-4157-9245-2c8b2c2eb973', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '시너지 효과는 그 시너지를 가진 소환수들에게 적용되며, 효과 중에는 소환수의 능력치에 영향을 주는 것도 있다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('ae72b393-75bc-4c50-a6d5-7189f872bda2', '7f0ecb1f-845b-42c3-88f1-0e8212d8b5f0', null, '시너지 효과의 활성 여부는 전투를 시작하는 시점의 카운트로 확정되고, 활성화된 효과는 그 전투 페이즈 내내 계속 적용된다. 〔함의〕', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('6f86d736-14f6-4829-98a4-6bafa491b28a', '237c54e1-f164-4078-b163-74b5cfa544b8', null, '심상 효과의 구체 내용·수치와 효과 형태(예: 같은 심상 강화·전체 약한 버프 등)는 시스템이 고정하지 않고 콘텐츠·밸런스·스케일링 기획에서 정한다.', '완료', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('0f0e9dd0-3cdc-4990-a108-b0b2820388fa', '237c54e1-f164-4078-b163-74b5cfa544b8', null, '심상 효과가 전장에서 적용되는 강도는 전장에 진입하는 시점에 이미 소환술사의 육성 상태로 결정돼 있다.', '미구현', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('55559029-3f46-48eb-abe4-16c71e92ee3e', '631b0880-f6c4-4c53-b9b4-191cdd86d9c6', null, '전장을 시작할 때 풀에서 5개의 소환수 특성이 뽑혀 소환수 종류들에 무작위로 배정된다.', '오구현', '오구현 : 전장마다 5종의 특성만 등장해 배정돼야 하는데, 종류마다 제각각 특성이 붙어 한 전장에 5종보다 많은 특성이 나온다', 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1ffccbf9-39db-4cec-afe8-8b694a520bf1', '631b0880-f6c4-4c53-b9b4-191cdd86d9c6', null, '소환수 특성은 개체가 아니라 소환수 종류 단위로 부여되며, 한 전장 안에서는 바뀌지 않는다(같은 종류는 마릿수와 무관하게 같은 특성).', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('defd3db2-2003-4069-8841-4b0050f7694a', '631b0880-f6c4-4c53-b9b4-191cdd86d9c6', null, '같은 종류의 소환수는 합성하거나 추가로 더 소환해도 이미 부여된 소환수 특성을 그대로 유지한다.', '완료', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('9f9f9857-5969-4951-9bd9-5ee5174432bc', '631b0880-f6c4-4c53-b9b4-191cdd86d9c6', null, '전장이 바뀌면 소환수 특성을 처음부터 다시 배정한다(같은 종류라도 다른 전장에서는 다른 특성일 수 있다).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7c76039d-b6e5-4ba9-a0e4-cd66c534ef2f', '631b0880-f6c4-4c53-b9b4-191cdd86d9c6', null, '소환수 특성을 부여할 확률은 소환수의 역할군에 따라 보정되며, 특성별 역할군 우선 배정 규칙·확률은 소환수 특성 콘텐츠가 나와야 정해지므로 콘텐츠 기획에서 정한다.', '미구현', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('38e2aa85-3cc5-42fe-bbdf-7d09cbffa37b', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 정보 UI는 시너지 인디케이터, 시너지 상세 정보, 시너지 맵 세 가지로 구성된다.', '미구현', null, 0);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('601528d3-8b5a-49e1-8bf2-65e7e5fb9fff', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 인디케이터는 전장 왼쪽 상단에 표시되며, 각 시너지를 고유 아이콘과 활성 정도 표시로 나타낸다.', '완료', null, 1);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('90b47c2e-7318-4986-83f7-da52d2247b94', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 아이콘은 그 시너지가 활성화되면 색상으로, 활성화되지 않았으면 흑백으로 표시해 플레이어가 켜짐 여부를 알 수 있게 한다.', '미구현', null, 2);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('63a60442-bd45-4607-ba41-a990ed3546a3', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '인디케이터는 시너지의 최대치 대비 현재 활성 정도를 막대(bar) 형태로 보여준다(막대 상세 디자인은 디자인 기획).', '완료', null, 3);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f6ef6b76-a768-42e0-b6a1-af0ad9650ac7', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '인디케이터는 현재 전장에 존재하는 소환수들의 시너지만 보여주며, 아직 활성화되지 않았더라도 카운트가 1 이상으로 존재하는 시너지는 보여준다.', '완료', null, 4);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f956e1a7-02a5-4a15-b319-ef1c1bbf8e49', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '인디케이터는 시너지의 활성 정도 순으로 정렬하며, 활성 정도가 같으면 시너지 id 순으로 정렬한다.', '오구현', '오구현 : 활성 정도가 같으면 정해진 시너지 순서로 정렬돼야 하는데, 배치된 소환수 수가 많은 시너지가 먼저 정렬된다', 5);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('a4272a53-237c-470c-8c6f-decef1aa53ef', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '플레이어가 인디케이터의 시너지 아이콘을 클릭하면 그 시너지의 상세 정보를 볼 수 있다.', '완료', null, 6);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('79e3c4a8-048a-4333-81e1-d8f66d2765c6', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 상세 정보는 시너지 아이콘, 수치를 포함한 상세 설명, 그리고 그 시너지에 소속된 소환수 목록을 보여준다.', '완료', null, 7);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('5477e3ba-6434-41b2-851d-ba156c42ab29', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '소속 소환수 목록은 소환수 프로필로 나열하며, 전장에 배치되어 시너지 활성에 기여하는 소환수는 밝게, 그렇지 않은 소환수는 어둡게 표시한다.', '완료', null, 8);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('1b2edc03-4fe8-49fc-9a24-fb051b41da01', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 맵은 현재 전장의 시너지 분배 상태를 2차원 좌표로 보여준다 — 가로축은 심상 효과, 세로축은 소환수 특성이다.', '미구현', null, 9);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('7523d5b1-1fe0-456f-ba74-f0dc5df55491', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 맵은 각 소환수의 프로필 아이콘을 그 소환수가 가진 (심상 효과 × 소환수 특성) 좌표에 배치해 보여준다.', '미구현', null, 10);
insert into ur (id, feature_id, ur_group_id, text, status, misimpl_reason, sort_order) values ('f6b72a22-aa9d-46be-a8b0-84f92f4ca02f', '040cc75e-1094-49c9-8e14-2cb6def2a9de', null, '시너지 맵은 화면 왼쪽 상단의 ''시너지 맵 보기'' 버튼으로 열 수 있다.', '미구현', null, 11);
